const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security middleware
app.use(helmet()); // Security headers

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.'
});

app.use(limiter);

// Request logging (only in development)
if (process.env.NODE_ENV === 'development') {
  app.use((req, res, next) => {
    console.log(`${new Date().toISOString()} - ${req.ip} - ${req.method} ${req.path}`);
    next();
  });
}

// Set timeout for requests
app.use((req, res, next) => {
  req.setTimeout(30000, () => {
    res.status(408).json({ error: 'Request timeout' });
  });
  next();
});

// Health check with error handling
app.get('/health', (req, res) => {
  try {
    // Validate request
    if (req.query && Object.keys(req.query).length > 5) {
      return res.status(400).json({ error: 'Too many query parameters' });
    }

    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      version: process.env.npm_package_version || '1.0.0'
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Input validation
    const page = req.query.page ? parseInt(req.query.page) : 1;
    const limit = req.query.limit ? parseInt(req.query.limit) : 10;

    // Validate and sanitize inputs
    if (isNaN(page) || page < 1) {
      return res.status(400).json({ error: 'Invalid page parameter' });
    }

    if (isNaN(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({ error: 'Limit must be between 1 and 100' });
    }

    // Filter users based on query parameters safely
    let users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Simple filtering (only allow filtering by name)
    if (req.query.name) {
      const nameFilter = req.query.name.toString().toLowerCase();
      if (nameFilter.length < 50) { // Prevent excessively long inputs
        users = users.filter(user => 
          user.name.toLowerCase().includes(nameFilter)
        );
      }
    }

    // Pagination
    const startIndex = (page - 1) * limit;
    const endIndex = page * limit;
    const results = users.slice(startIndex, endIndex);

    res.json({
      page,
      limit,
      total: users.length,
      totalPages: Math.ceil(users.length / limit),
      data: results
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Handle 404 for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  // Hide sensitive error details in production
  const isProd = process.env.NODE_ENV === 'production';

  res.status(error.status || 500).json({
    error: isProd ? 'Internal server error' : error.message || 'Unknown error'
  });
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received. Shutting down gracefully...');
  process.exit(0);
});

process.on('SIGINT', () => {
  console.log('SIGINT received. Shutting down gracefully...');
  process.exit(0);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

module.exports = app;
module.exports.server = server;

