const url = require('url');

// Function to parse .env file
function parseEnvFile(filePath) {
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    const env = {};

    content.split('\n').forEach(line => {
      // Match lines that look like KEY=VALUE
      const matches = line.match(/^([^#=]+)=(.*)$/);
      if (matches) {
        let value = matches[2];

        // Remove surrounding quotes if present
        if (value.startsWith('"') && value.endsWith('"')) {
          value = value.slice(1, -1);
        }

        env[matches[1].trim()] = value.trim();
      }
    });

    return env;
  } catch (error) {
    console.log(`❌ Error reading ${filePath}:`, error.message);
    return {};
  }
}

// Load environment variables from .env.test
const env = parseEnvFile('.env.test');

// Helper function to redact sensitive values for display
function redactValue(value, showEndChars = 4) {
  if (!value) return 'undefined';
  const hideLength = Math.max(0, value.length - showEndChars - 4);
  return value.substring(0, 4) + '*'.repeat(hideLength) + value.slice(-showEndChars);
}

