const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"]
    }
  },
  // Prevent clickjacking
  frameguard: { action: 'deny' },
  // Prevent XSS attacks
  xssFilter: true,
  // Prevent sniffing of MIME types
  nosniff: true,
}));

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Parse JSON bodies
app.use(express.json({
  limit: '10kb' // Limit request size
}));

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  // Validate query parameters if present
  if (req.query.page && isNaN(parseInt(req.query.page))) {
    return res.status(400).json({
      error: 'Invalid page parameter'
    });
  }
  if (req.query.limit && (isNaN(parseInt(req.query.limit)) || parseInt(req.query.limit) > 100)) {
    return res.status(400).json({
      error: 'Invalid limit parameter (max 100)'
    });
  }
  next();
};

// Apply validation to routes that might have query parameters
app.use(['/users'], validateQueryParams);

// Health check endpoint - could include more detailed system information in the future
app.get('/health', (req, res) => {
  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    uptime: process.uptime()
  });
});

// Users endpoint with potential for pagination and filtering
app.get('/users', (req, res) => {
  try {
    // In a real application, this would query a database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Simple pagination if requested
    let result = users;
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;

    if (page && limit) {
      const startIndex = (page - 1) * limit;
      const endIndex = page * limit;
      result = users.slice(startIndex, endIndex);
    }

    res.json({
      data: result,
      pagination: {
        page: page,
        limit: limit,
        total: users.length,
        pages: Math.ceil(users.length / limit)
      }
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// Catch 404 errors
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.originalUrl} not found`
  });
});

// Global error handling middleware
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Determine status code based on error type
  const statusCode = error.statusCode || 500;

  // Don't leak sensitive error details in production
  const response = {
    error: process.env.NODE_ENV === 'production' ?
      'Internal server error' : error.message
  };

  if (process.env.NODE_ENV !== 'production') {
    response.stack = error.stack;
  }

  res.status(statusCode).json(response);
});

// Configure server
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('Unhandled Promise Rejection:', err);
  server.close(() => process.exit(1));
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('Uncaught Exception:', err);
  server.close(() => process.exit(1));
});

module.exports = app;

