const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security
corsOptions = {
  origin: process.env.ALLOWED_ORIGINS || 'https://your-trusted-domain.com',
  optionsSuccessStatus: 200
};
app.use(cors(corsOptions)); // Configure CORS properly

// Rate limiting to prevent DOS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Input validation middleware (can be expanded)
const validateQueryParams = (req, res, next) => {
  // Example: Validate that query parameters don't contain dangerous patterns
  Object.keys(req.query).forEach(key => {
    const value = req.query[key];
    // Simple SQL injection prevention
    if (typeof value === 'string' && /('|--|\\/|;)/i.test(value)) {
      return res.status(400).json({
        error: 'Invalid characters in query parameters'
      });
    }
  });
  next();
};

// Use input validation on routes that might accept query parameters
app.use('/users', validateQueryParams);

// Health check endpoint (no input, minimal risk)
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      status: 'error'
    });
  }
});

// Users endpoint with potential for query parameters
app.get('/users', (req, res) => {
  try {
    // In a real app, this would query a database with proper sanitization
    // For now, return static data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Example of handling query parameters safely
    const limit = req.query.limit ? parseInt(req.query.limit) : null;
    if (limit !== null && (isNaN(limit) || limit <= 0)) {
      return res.status(400).json({
        error: 'Limit must be a positive number'
      });
    }

    const result = limit ? users.slice(0, limit) : users;
    res.json(result);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Internal server error'
    });
  }
});

// 404 handler for unknown routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    error: 'Internal server error'
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

