async function testApiKey(service, baseUrl, apiKey, apiKeyHeader = 'Authorization') {
  console.log(`\nTesting ${service} API...`);

  return new Promise((resolve) => {
    const options = {
      hostname: baseUrl,
      path: '/v1/models', // Minimal endpoint that requires auth
      method: 'GET',
      headers: {
        [apiKeyHeader]: apiKey.startsWith('Bearer ') ? apiKey : `Bearer ${apiKey}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode === 200) {
          console.log(`✓ ${service}: CONNECTED`);
          resolve(true);
        } else {
          console.log(`✗ ${service}: INVALID CREDENTIALS (Status: ${res.statusCode})`);
          resolve(false);
        }
      });
    });

    req.on('error', (error) => {
      console.log(`✗ ${service}: CONNECTION FAILED`);
      resolve(false);
    });

    // Add timeout to prevent hanging
