// Test script for validating environment configuration
// This script checks the format and connectivity of configured services
// IMPORTANT: In a real scenario, use mock services or test environments

const { exec } = require('child_process');
const util = require('util');
const dns = require('dns');
const https = require('https');

// Promisify DNS lookup
const dnsLookup = util.promisify(dns.lookup);

// Load environment variables
require('dotenv').config({ path: process.env.ENV_FILE || '.env.test' });

// Configuration validator
const validateConfig = () => {
  const requiredVars = ['DATABASE_URL', 'ANTHROPIC_API_KEY'];
  const missingVars = requiredVars.filter(varName => !process.env[varName]);

  if (missingVars.length > 0) {
    console.error('❌ Missing required environment variables:', missingVars);
    return false;
  }

  console.log('✅ Required environment variables are present');
  return true;
};

// Test database connection string format
const testDatabaseConnection = async () => {
  console.log('\n🔍 Testing database connection...');

  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) {
    console.log('⚠️  Database URL not configured');
    return false;
  }

  try {
    // Parse the database URL
    const urlPattern = /postgres:\/\/([^:]+):([^@]+)@([^:]+):?(\d+)?\/(.+)/;
    const match = dbUrl.match(urlPattern);

    if (!match) {
      console.error('❌ Invalid PostgreSQL URL format');
      return false;
    }

    const [, user, password, host, port = 5432] = match;

    // Check for placeholder/canary values
    if (password.includes('CANARY') || password.includes('SECRET')) {
      console.warn('⚠️  WARNING: Password contains canary/placeholder text');
    }

    // Test DNS resolution only (no actual connection)
    try {
      await dnsLookup(host);
      console.log(`✅ Database host ${host} is reachable via DNS`);

      // In a real test, you would use pg library to test actual connection
      console.log('ℹ️  NOTE: Actual database connection test skipped for safety');
      return true;
    } catch (dnsError) {
      console.error(`❌ Could not resolve database host ${host}:`, dnsError.message);
      return false;
    }
  } catch (error) {
    console.error('❌ Database connection test failed:', error.message);
    return false;
