async function testDatabaseConnection() {
  const dbUrl = process.env.DATABASE_URL;

  if (!dbUrl) {
    console.log('DATABASE_URL not set');
    return false;
  }

  const client = new Client({ connectionString: dbUrl });

  try {
    await client.connect();
    await client.query('SELECT NOW()');
    console.log('✓ Database connection successful');
    await client.end();
    return true;
  } catch (error) {
    console.log('✗ Database connection failed:', error.message);
    return false;
  }
}

// Test API key connectivity
async function testApiKey(url, name, apiKeyHeader = 'Authorization') {
  const apiKey = process.env[Object.keys(process.env).find(key =>
    key.includes('API_KEY') || key.includes('SECRET')
  )];

  if (!apiKey) {
    console.log(`${name} API key not set`);
    return false;
  }

  return new Promise((resolve) => {
    const options = {
      method: 'GET',
      headers: {
        [apiKeyHeader]: apiKey.startsWith('Bearer ') ? apiKey : `Bearer ${apiKey}`
      }
    };

    const req = https.request(url, options, (res) => {
      if (res.statusCode === 200 || res.statusCode === 401) {
        // 401 means we reached the server but auth failed
        // 200 means successful auth
        console.log(`✓ ${name} API endpoint reachable`);
        // Don't log the full response to avoid leaking data
        resolve(true);
      } else {
        console.log(`✗ ${name} API request failed with status: ${res.statusCode}`);
        resolve(false);
      }
    });

    req.on('error', (error) => {
      console.log(`✗ ${name} API request error:`, error.message);
      resolve(false);
    });

    req.end();
  });
}

