const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const { body, query, validationResult } = require('express-validator');

const app = express();

// Security middleware
app.use(helmet()); // Security headers
app.use(helmet.permittedCrossDomainPolicies()); // Additional security

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || '*',
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization']
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in headers
  legacyHeaders: false, // Disable X-RateLimit headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Request size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Input validation middleware for users route
const validateUserParams = [
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .withMessage('Limit must be between 1 and 100')
    .toInt(),
  query('page')
    .optional()
    .isInt({ min: 1 })
    .withMessage('Page must be a positive integer')
    .toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ 
        errors: errors.array().map(err => ({
          field: err.param,
          message: err.msg
        })) 
      });
    }
    next();
  }
];

// Health check endpoint
app.get('/health', [
  // Validate query parameters if any
  query('verbose')
    .optional()
    .isBoolean()
    .withMessage('Verbose must be a boolean value'),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ 
        errors: errors.array().map(err => ({
          field: err.param,
          message: err.msg
        })) 
      });
    }
    next();
  }
], (req, res) => {
  try {
    const healthData = {
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    };

    // Add verbose information if requested
    if (req.query.verbose === 'true') {
      healthData.hostname = require('os').hostname();
      healthData.platform = process.platform;
      healthData.version = process.version;
    }

    res.json(healthData);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      status: 'error', 
      message: 'Internal server error'
    });
  }
});

// Users endpoint with improved validation and error handling
app.get('/users', validateUserParams, (req, res) => {
  try {
    // Simulated user data (in real app, this would come from a database)
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Extract pagination parameters (with defaults)
    const limit = req.query.limit || 10;
    const page = req.query.page || 1;
    const offset = (page - 1) * limit;

    // Apply pagination
    const paginatedUsers = mockUsers.slice(offset, offset + limit);

    // Return response with pagination metadata
    res.json({
      data: paginatedUsers,
      pagination: {
        page: page,
        limit: limit,
        total: mockUsers.length,
        pages: Math.ceil(mockUsers.length / limit)
      }
    });
  } catch (error) {
    console.error('Error retrieving users:', error);
    res.status(500).json({ 
      status: 'error', 
      message: 'Failed to retrieve users'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    status: 'error',
    message: `Cannot ${req.method} ${req.originalUrl}`
  });
});

