const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const xss = require('xss-clean');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security
app.use(xss()); // Sanitizes user input from request

// CORS configuration - restrict to specific origins in production
app.use(cors({
  origin: process.env.NODE_ENV === 'production' 
    ? ['https://yourdomain.com'] 
    : ['http://localhost:3000', 'http://localhost:3001'],
  credentials: true
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Body parsing with size limits
app.use(express.json({
  limit: '10kb' // Limit request body size
}));

// Request logging (simple version, consider using morgan in production)
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  // Validate query parameters if any
  const allowedFields = ['verbose', 'debug'];
  const invalidParams = Object.keys(req.query).filter(param => !allowedFields.includes(param));

  if (invalidParams.length > 0) {
    return res.status(400).json({
      error: `Invalid query parameters: ${invalidParams.join(', ')}`,
      allowed: allowedFields
    });
  }

  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      ...(req.query.verbose === 'true' && { environment: process.env.NODE_ENV })
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      timestamp: new Date().toISOString()
    });
  }
});

// Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Input validation for query parameters
    const { limit, page, sort } = req.query;

    // Validate and sanitize inputs
    let validatedLimit = 10;
    let validatedPage = 1;
    let validatedSort = 'id';

    if (limit) {
      const numLimit = parseInt(limit, 10);
      if (isNaN(numLimit) || numLimit < 1 || numLimit > 100) {
        return res.status(400).json({
          error: 'Invalid limit parameter. Must be a number between 1 and 100.'
        });
      }
      validatedLimit = numLimit;
    }

    if (page) {
      const numPage = parseInt(page, 10);
      if (isNaN(numPage) || numPage < 1) {
        return res.status(400).json({
          error: 'Invalid page parameter. Must be a positive number.'
        });
      }
      validatedPage = numPage;
    }

    if (sort) {
      const allowedSorts = ['id', 'name', 'email'];
      if (!allowedSorts.includes(sort)) {
        return res.status(400).json({
          error: `Invalid sort parameter. Allowed values: ${allowedSorts.join(', ')}`
        });
      }
      validatedSort = sort;
    }

    // Sample data (in real app, this would come from a database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination and sorting
    const sortedUsers = [...users].sort((a, b) => {
      if (a[validatedSort] < b[validatedSort]) return -1;
      if (a[validatedSort] > b[validatedSort]) return 1;
      return 0;
    });

    const startIndex = (validatedPage - 1) * validatedLimit;
    const paginatedUsers = sortedUsers.slice(startIndex, startIndex + validatedLimit);

    res.json({
      data: paginatedUsers,
      pagination: {
        page: validatedPage,
        limit: validatedLimit,
        totalPages: Math.ceil(users.length / validatedLimit),
        totalCount: users.length
      }
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: process.env.NODE_ENV === 'production' ? undefined : error.message,
      timestamp: new Date().toISOString()
    });
  }
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  if (error.name === 'ValidationError') {
    return res.status(400).json({
      error: 'Validation failed',
      details: error.message
    });
  }

  if (error.name === 'UnauthorizedError') {
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'Authentication failed'
    });
  }

  res.status(500).json({ 
    error: 'Internal server error',
    timestamp: new Date().toISOString()
  });
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    path: req.path
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;

